const crypto = require('crypto');

// AWS Credentials
const accessKeyId = '[YOUR_AWS_ACCESS_KEY]';
const secretAccessKey = '[YOUR_AWS_SECRET_KEY]';

const region = 'us-east-1';
const service = 'invoicing';

// Get input data
const input = $input.all()[0].json;
const accountId = input.account_id;
const billingMonth = input.billing_month;
const billingYear = input.billing_year;

// Request details
const host = 'invoicing.us-east-1.api.aws';
const method = 'POST';
const canonicalUri = '/';
const canonicalQuerystring = '';
const amzTarget = 'Invoicing.ListInvoiceSummaries';
const contentType = 'application/x-amz-json-1.0';

// Request body
const requestBody = JSON.stringify({
  Selector: {
    ResourceType: 'ACCOUNT_ID',
    Value: accountId
  },
  Filter: {
    BillingPeriod: {
      Month: billingMonth,
      Year: billingYear
    }
  },
  MaxResults: 10
});

// Create date strings
const now = new Date();
const amzDate = now.toISOString().replace(/[:-]|\.\d{3}/g, '').slice(0, 15) + 'Z';
const dateStamp = amzDate.slice(0, 8);

// Create canonical headers (must be sorted alphabetically)
const canonicalHeaders = 
  'content-type:' + contentType + '\n' +
  'host:' + host + '\n' +
  'x-amz-date:' + amzDate + '\n' +
  'x-amz-target:' + amzTarget + '\n';

const signedHeaders = 'content-type;host;x-amz-date;x-amz-target';

// Hash the payload
const payloadHash = crypto.createHash('sha256').update(requestBody).digest('hex');

// Create canonical request
const canonicalRequest = 
  method + '\n' +
  canonicalUri + '\n' +
  canonicalQuerystring + '\n' +
  canonicalHeaders + '\n' +
  signedHeaders + '\n' +
  payloadHash;

// Create string to sign
const algorithm = 'AWS4-HMAC-SHA256';
const credentialScope = dateStamp + '/' + region + '/' + service + '/aws4_request';
const stringToSign = 
  algorithm + '\n' +
  amzDate + '\n' +
  credentialScope + '\n' +
  crypto.createHash('sha256').update(canonicalRequest).digest('hex');

// Create signing key
function getSignatureKey(key, dateStamp, regionName, serviceName) {
  const kDate = crypto.createHmac('sha256', 'AWS4' + key).update(dateStamp).digest();
  const kRegion = crypto.createHmac('sha256', kDate).update(regionName).digest();
  const kService = crypto.createHmac('sha256', kRegion).update(serviceName).digest();
  const kSigning = crypto.createHmac('sha256', kService).update('aws4_request').digest();
  return kSigning;
}

const signingKey = getSignatureKey(secretAccessKey, dateStamp, region, service);
const signature = crypto.createHmac('sha256', signingKey).update(stringToSign).digest('hex');

// Create authorization header
const authorizationHeader = 
  algorithm + ' ' +
  'Credential=' + accessKeyId + '/' + credentialScope + ', ' +
  'SignedHeaders=' + signedHeaders + ', ' +
  'Signature=' + signature;

return [{
  json: {
    url: 'https://' + host + '/',
    method: 'POST',
    headers: {
      'Content-Type': contentType,
      'X-Amz-Date': amzDate,
      'X-Amz-Target': amzTarget,
      'Authorization': authorizationHeader
    },
    body: requestBody
  }
}];

const response = $input.first().json;
const data = JSON.parse(response.data);
const invoices = data.InvoiceSummaries || [];

return invoices.map(invoice => ({
  json: invoice
}));

// Get cutoff date from Set Test Data node
const cutoffDate = new Date($node['Calculate Last Month Date Range'].json.cutoff_date + 'T00:00:00.000Z');

// Get all invoice items
const items = $input.all();

// Filter invoices by issued date
const filtered = items.filter(item => {
  const issuedDate = new Date(item.json.IssuedDate * 1000);
  return issuedDate >= cutoffDate;
});

// Return filtered items or empty message
if (filtered.length === 0) {
  return [{ json: { message: 'No invoices after cutoff date' } }];
}

return filtered;

const invoice = $('Loop Over Invoices').item.json;

// Helper function to convert Unix timestamp to YYYY-MM-DD
function formatDate(timestamp) {
  if (!timestamp || isNaN(timestamp)) {
    throw new Error(`Invalid timestamp: ${timestamp}`);
  }
  const date = new Date(timestamp * 1000);
  if (isNaN(date.getTime())) {
    throw new Error(`Could not create valid date from timestamp: ${timestamp}`);
  }
  return date.toISOString().split('T')[0];
}

// AWS has the dates backwards - DueDate is earlier than IssuedDate
// So we use DueDate as dated_on and IssuedDate as due_on
const bill = {
  contact: 'https://api.freeagent.com/v2/contacts/[YOUR_FREEAGENT_CONTACT_ID]',
  reference: invoice.InvoiceId,
  dated_on: formatDate(invoice.DueDate),
  due_on: formatDate(invoice.IssuedDate),
  total_value: invoice.PaymentCurrencyAmount.TotalAmount,
  bill_items: [
    {
      category: 'https://api.freeagent.com/v2/categories/[YOUR_FREEAGENT_CATEGORY_ID]',
      description: `AWS Services - ${invoice.BillingPeriod.Year}-${String(invoice.BillingPeriod.Month).padStart(2, '0')}`,
      total_value: invoice.PaymentCurrencyAmount.TotalAmount,
      sales_tax_rate: '20.0'
    }
  ]
};

return { json: { bill } };

const billUrl = $json.bill.url;
const billAmount = $json.bill.total_value;
const billDate = $json.bill.dated_on;

const payment = {
  bank_transaction_explanation: {
    bank_account: 'https://api.freeagent.com/v2/bank_accounts/[YOUR_FREEAGENT_BANK_ACCOUNT_ID]',
    paid_bill: billUrl,
    dated_on: billDate,
    gross_value: `-${billAmount}`
  }
};

return { json: payment };

// Get last month's billing period
const now = new Date();
const lastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);

const billingYear = lastMonth.getFullYear();
const billingMonth = lastMonth.getMonth() + 1; // JavaScript months are 0-indexed

// Cutoff date is the first day of the billing period
const cutoffDate = `${billingYear}-${String(billingMonth).padStart(2, '0')}-01`;

return [{
  json: {
    billing_year: billingYear,
    billing_month: billingMonth,
    account_id: '[YOUR_AWS_ACCOUNT_ID]',
    cutoff_date: cutoffDate
  }
}];
